INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '12776751-2897-4d85-a4df-f4beb3d02368',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elixir Dependency Management — Lock Files, Versioning, and Hex Audits$escape$,
  $escape$Elixir's dependency story lives across two files: `mix.exs` declares requirements, `mix.lock` pins exact resolved versions. Never skip committing `mix.lock` — it ensures every team member and CI node runs identical dependency graphs. Version constraints use Hex's `~>` pessimistic operator: `~> 1.2` allows `>= 1.2.0 and < 2.0.0`, while `~> 1.2.3` tightens it to `>= 1.2.3 and < 1.3.0`. Prefer the patch-level form for libraries with unstable minor APIs. Run `mix deps.update --all` to regenerate the lock file against the latest allowed versions, then review the diff carefully. For security auditing, `mix hex.audit` checks your locked dependencies against Hex's advisory database — it exits non-zero on vulnerabilities, making it CI-friendly. `mix hex.outdated` shows which packages have newer releases outside your constraints, useful for scheduled dependency hygiene PRs. Lock file conflicts after a rebase? Delete it, run `mix deps.get`, and re-commit — Mix regenerates it deterministically.$escape$,
  $escape$# mix.exs — idiomatic version pinning
defp deps do
  [
    {:phoenix, "~> 1.7.14"},
    {:ecto_sql, "~> 3.11"},
    {:jason, "~> 1.4"},
    {:bandit, "~> 1.2"}
  ]
end

# Audit locked deps for known vulnerabilities (CI-safe)
# mix hex.audit

# Check what's outdated beyond your constraints
# mix hex.outdated

# Update a single dep and refresh mix.lock
# mix deps.update phoenix$escape$,
  $escape$bash$escape$,
