INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '49e045b0-a536-4afd-b576-e5a2f9583772',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elixir Dev Tooling — IEx, dbg/1, and ElixirLS in Practice$escape$,
  $escape$Elixir's `iex -S mix` drops you into a live REPL bound to your running application. You can recompile on the fly with `r(MyModule)` and inspect process state without restarting. For debugging, Elixir 1.14 introduced the `dbg/1` macro — a smarter alternative to `IO.inspect/2` that prints the expression, its AST-expanded form, and its value, including through pipes. Drop `|> dbg()` anywhere in a pipeline and each step is traced. For breakpoints, `IEx.pry()` pauses execution and hands control to an IEx session inside the calling process — useful but limited to synchronous flows. For OTP processes, reach for `:debugger.start()` and `:int.ni(MyModule)` to use the Erlang graphical debugger with full process visibility. On the LSP side, ElixirLS remains the standard — it resolves macros, understands `use` expansions, and provides `Go to Definition` across umbrella apps. Pair it with `next-ls` if you need faster indexing on large codebases. Set `elixirLS.suggestSpecs: true` to auto-generate `@spec` annotations from inferred types.$escape$,
  $escape$# Pipeline debugging with dbg/1 (Elixir 1.14+)
"hello world"
|> String.upcase()
|> String.split()
|> Enum.map(&String.reverse/1)
|> dbg()

# IEx.pry breakpoint (run with: iex -S mix)
def process(data) do
  require IEx
  IEx.pry()  # execution halts; inspect `data` in live IEx session
  transform(data)
end

# Erlang debugger for GenServer internals
:debugger.start()
:int.ni(MyApp.Worker)$escape$,
  $escape$bash$escape$,
