INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '48769c9b-cd76-4335-a0ba-2a4c1be9e2e2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elixir Deployments — OTP Releases, Multi-Stage Docker, and Runtime Dependencies$escape$,
  $escape$`mix release` bundles your app, its dependencies, and the Erlang runtime system (ERTS) into a self-contained OTP release under `_build/prod/rel/<app>/`. The resulting artifact needs no Elixir or Mix installed in production — only the OS-level shared libraries the BEAM links against (libc, libcrypto, etc.).

For Docker, use a multi-stage build: compile in a `hexpm/elixir` builder image with the full toolchain, then copy the release into a slim runtime image. The `hexpm/elixir:1.16.2-erlang-26.2-debian-bookworm-slim` builder produces a release that runs cleanly on `debian:bookworm-slim` — matching libc versions is critical. Alpine (musl libc) requires an OTP build targeting musl; mismatches cause cryptic NIF load failures at startup.

Configure runtime secrets via `config/runtime.exs` using `System.fetch_env!/1` — never bake them into the compiled artifact through `config/config.exs`. Run `mix release --overwrite` in CI pipelines. The final runtime image typically lands at 50–80 MB versus the 1.5 GB builder stage, making it cache-friendly and fast to pull.$escape$,
  $escape$# Stage 1: Build
FROM hexpm/elixir:1.16.2-erlang-26.2-debian-bookworm-slim AS builder
WORKDIR /app
ENV MIX_ENV=prod
RUN mix do local.hex --force, local.rebar --force
COPY mix.exs mix.lock ./
RUN mix deps.get --only prod
COPY . .
RUN mix release --overwrite

# Stage 2: Runtime (no Elixir/Mix needed)
FROM debian:bookworm-slim AS runtime
RUN apt-get update && apt-get install -y libssl3 libncurses6 \
    && rm -rf /var/lib/apt/lists/*
WORKDIR /app
COPY --from=builder /app/_build/prod/rel/my_app ./
CMD ["./bin/my_app", "start"]$escape$,
  $escape$bash$escape$,
